SELECT COUNT(*) AS TOTAL FROM SERVIDOR_PROJ SP JOIN PROJ P ON P.PK = SP.FK_PROJ JOIN SERVIDOR S ON S.PK_SIAPE = SP.FK_SIAPE WHERE LOWER(S.GENERO) = LOWER('masculino') AND LOWER(S.SIGLA_CAMPUS) = LOWER('luz') AND LOWER(SP.PAPEL) = LOWER('autor') AND LOWER(P.TIPO_PROJETO) = LOWER('ensino') AND SP.DATA_ENTRADA >= DATE('now', '-5 years') AND SP.DATA_ENTRADA <= DATE('now')